#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    // consume the newline after T
    int c = getchar();
    for (int tc = 0; tc < T; ++tc) {
        char line[5000];
        if (!fgets(line, sizeof(line), stdin)) break;
        // remove possible trailing newline
        line[strcspn(line, "\n")] = '\0';
        int sum = 0, cnt = 0;
        char *token = strtok(line, " ");
        while (token) {
            int val = atoi(token);
            sum += val;
            ++cnt;
            token = strtok(NULL, " ");
        }
        int need = (4 * cnt + 4) / 5; // ceil(4*cnt/5)
        if (sum >= need) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

