const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
if (input.length === 0) process.exit(0);
const T = parseInt(input[0].trim(), 10);
let out = [];
for (let i = 1; i <= T; ++i) {
  let line = input[i] || '';
  line = line.trim();
  if (line.length === 0) { out.push('NO'); continue; }
  const parts = line.split(/\s+/);
  let sum = 0;
  for (const p of parts) {
    sum += Number(p);
  }
  const cnt = parts.length;
  const need = Math.floor((4 * cnt + 4) / 5); // ceil(4*cnt/5)
  out.push(sum >= need ? 'YES' : 'NO');
}
console.log(out.join('\n'));
